import{c as a,Q as e,j as r,m as n}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"lg5spring","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":1778943603000}'),s={name:"index.md"};function d(i,t,o,c,l,g){return e(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="lg5spring" tabindex="-1"><span class="prefix">lg5</span><span class="accent">spring</span> <a class="header-anchor" href="#lg5spring" aria-label="Permalink to &quot;&lt;span class=&#39;prefix&#39;&gt;lg5&lt;/span&gt;&lt;span class=&#39;accent&#39;&gt;spring&lt;/span&gt;&quot;">​</a></h1><p><span class="tagline">Spring Boot 3.5 + JDK 21 — Framework for Building Microservices Faster</span></p><div class="badge-group"><span class="badge badge-spring">Spring Boot 3.5</span><span class="badge badge-java">JDK 21</span><span class="badge badge-kotlin">Kotlin 2.2</span><span class="badge badge-grape">Gradle Kotlin</span></div><div class="feature-grid"><div class="feature-card"><div class="feature-icon">🚀</div><div class="feature-content"><h3>Hexagonal Architecture</h3><p>Hexagonal/Ports-and-Adapters con DDD aplicado en cada capa del proyecto.</p></div></div><div class="feature-card"><div class="feature-icon">⚡</div><div class="feature-content"><h3>Event-Driven</h3><p>Kafka + Avro + Outbox Pattern para mensajería asíncrona confiable.</p></div></div><div class="feature-card"><div class="feature-icon">🧡</div><div class="feature-content"><h3>Distributed SAGAs</h3><p>Patrón Saga para transacciones distribuidas con compensación automática.</p></div></div><div class="feature-card"><div class="feature-icon">🧪</div><div class="feature-content"><h3>BDD Testing</h3><p>Cucumber + Testcontainers + Allure para A/TDD de extremo a extremo.</p></div></div><div class="feature-card"><div class="feature-icon">📦</div><div class="feature-content"><h3>Maven BOM</h3><p>Parent POM gestionado con dependencias versionadas centralizadamente.</p></div></div><div class="feature-card"><div class="feature-icon">⚙</div><div class="feature-content"><h3>Operabilidad</h3><p>Logging ELK, Sleuth tracing, Docker, JIB, Multi-arch images.</p></div></div></div><hr><h2 id="¿que-es-lg5-spring" tabindex="-1">¿Qué es lg5-spring? <a class="header-anchor" href="#¿que-es-lg5-spring" aria-label="Permalink to &quot;¿Qué es lg5-spring?&quot;">​</a></h2><p><strong>lg5-spring</strong> es un <strong>Framework BOM (Bill of Materials)</strong> de Lg Pentagon (LgLabs) diseñado para crear microservicios Spring Boot de forma rápida y estandarizada.</p><p>Es un conjunto de librerías, plantillas y estándares que te permiten enfocarte en el <strong>dominio de negocio</strong> en lugar de perder tiempo configurando dependencias, plugins de build, logging, testing, y patrones de arquitectura.</p><h3 id="stack-tecnico" tabindex="-1">Stack Técnico <a class="header-anchor" href="#stack-tecnico" aria-label="Permalink to &quot;Stack Técnico&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Componente</th><th>Versión</th></tr></thead><tbody><tr><td>Spring Boot</td><td>3.5.14</td></tr><tr><td>Spring Framework</td><td>6.2.2</td></tr><tr><td>JDK</td><td>21</td></tr><tr><td>Kotlin</td><td>2.2.0</td></tr><tr><td>Gradle</td><td>8.x (Kotlin DSL)</td></tr><tr><td>PostgreSQL</td><td>42.7.5</td></tr><tr><td>Kafka</td><td>spring-kafka 3.3.2 + Avro 1.12.0</td></tr><tr><td>Testcontainers</td><td>1.20.4</td></tr><tr><td>Cucumber</td><td>7.21.1</td></tr><tr><td>MapStruct</td><td>1.6.3</td></tr></tbody></table><h3 id="caracteristicas-principales" tabindex="-1">Características Principales <a class="header-anchor" href="#caracteristicas-principales" aria-label="Permalink to &quot;Características Principales&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Característica</th><th>Descripción</th></tr></thead><tbody><tr><td><strong>Arquitectura Hexagonal</strong></td><td>Ports-and-Adapters con DDD aplicado en cada capa</td></tr><tr><td><strong>Event-Driven</strong></td><td>Kafka + Avro + Outbox Pattern para mensajería asíncrona</td></tr><tr><td><strong>Sagas Distribuidas</strong></td><td>Compensación automática para transacciones distribuidas</td></tr><tr><td><strong>Testing E2E</strong></td><td>Unit → Integration → Acceptance (Cucumber BDD)</td></tr><tr><td><strong>Maven BOM</strong></td><td>Parent POM con dependencias versionadas centralizadamente</td></tr><tr><td><strong>El Operabilidad</strong></td><td>Logging ELK, Sleuth tracing, Docker images con JIB</td></tr></tbody></table><h3 id="modulos-del-framework" tabindex="-1">Módulos del Framework <a class="header-anchor" href="#modulos-del-framework" aria-label="Permalink to &quot;Módulos del Framework&quot;">​</a></h3><p>El framework está organizado en <strong>~20 submódulos Gradle</strong> que cubren todas las necesidades de un microservicio:</p><p><strong>Core:</strong> <code>lg5-spring-parent</code>, <code>lg5-spring-starter</code>, <code>lg5-spring-api-rest</code>, <code>lg5-spring-data-jpa</code>, <code>lg5-spring-client</code></p><p><strong>Messaging:</strong> <code>lg5-spring-kafka</code> (config, producer, consumer, model), <code>lg5-spring-outbox</code></p><p><strong>Patterns:</strong> <code>lg5-jvm-saga</code>, <code>lg5-common</code> (domain, application-service)</p><p><strong>Tools:</strong> <code>lg5-spring-logger</code>, <code>lg5-spring-utils</code>, <code>lg5-jvm-utils</code></p><p><strong>Testing:</strong> <code>lg5-spring-testcontainers</code>, <code>lg5-spring-integration-test</code>, <code>lg5-spring-acceptance-test</code>, <code>lg5-jvm-unit-test</code></p><h3 id="licencia" tabindex="-1">Licencia <a class="header-anchor" href="#licencia" aria-label="Permalink to &quot;Licencia&quot;">​</a></h3><p>Distribuido bajo la <a href="https://github.com/lg-labs-pentagon/lg5-spring/blob/main/LICENSE" target="_blank" rel="noreferrer">Licencia MIT</a>.</p>',21)])])}const h=a(s,[["render",d]]);export{u as __pageData,h as default};
